#include<bits/stdc++.h>
using namespace std;

int main()
{
	int l,s=0,i,n=0;
	scanf("%d",&l);
    for(i=2;i<=l;i++)
    {
    	int x=2;
    	while(x<=floor(sqrt(i))&&(i%x!=0))
    	x++;
    	if(x>floor(sqrt(i)))
    	{
    		if(s+i<=l)
    		{
    			s+=i;
    		    n++;
    		    printf("%d\n",i);
    		}
    		else
    		{
    			break;
    		}
    	}
    }
    printf("%d",n);
    return 0;
}
